use crate::api::client::ApiClient;
use crate::models::{ResultWithDefaultError, TimeEntry};
use crate::utilities;
use chrono::{Datelike, NaiveDate, Utc};
use std::collections::BTreeMap;
use std::io::{self, BufWriter, Write};

const BILLING_UNIT_SECONDS: i64 = 15 * 60;

pub struct BillWeeklyCommand;

fn billed_seconds(entry: &TimeEntry) -> Option<i64> {
    if !entry.billable || entry.stop.is_none() || entry.duration < 0 {
        return None;
    }

    Some(
        ((entry.duration + BILLING_UNIT_SECONDS - 1) / BILLING_UNIT_SECONDS) * BILLING_UNIT_SECONDS,
    )
}

fn week_monday(entry: &TimeEntry) -> NaiveDate {
    let date = entry.start.with_timezone(&Utc).date_naive();
    date - chrono::Duration::days(date.weekday().num_days_from_monday() as i64)
}

fn aggregate(entries: &[TimeEntry]) -> BTreeMap<NaiveDate, i64> {
    let mut weeks = BTreeMap::new();
    for entry in entries {
        if let Some(seconds) = billed_seconds(entry) {
            *weeks.entry(week_monday(entry)).or_insert(0) += seconds;
        }
    }
    weeks
}

impl BillWeeklyCommand {
    pub async fn execute(
        api_client: impl ApiClient,
        since: Option<String>,
        until: Option<String>,
    ) -> ResultWithDefaultError<()> {
        let (since, until) = utilities::normalize_time_entry_list_filters(since, until)?;
        let entries = api_client
            .get_time_entries_filtered_minimal(since, until)
            .await?;
        let weeks = aggregate(&entries);
        let total: i64 = weeks.values().sum();

        let stdout = io::stdout();
        let mut handle = BufWriter::new(stdout);
        if weeks.is_empty() {
            writeln!(handle, "(no data)").expect("failed to print");
        } else {
            for (monday, seconds) in weeks {
                writeln!(handle, "{}  {seconds}s", monday.format("%Y-%m-%d"))
                    .expect("failed to print");
            }
            writeln!(handle, "Total  {total}s").expect("failed to print");
        }
        Ok(())
    }
}

