mod tests {
    use super::*;
    use chrono::{DateTime, TimeZone};

    fn entry(start: &str, duration: i64, billable: bool, stop: bool) -> TimeEntry {
        TimeEntry {
            id: 1,
            description: String::new(),
            start: DateTime::parse_from_rfc3339(start)
                .unwrap()
                .with_timezone(&Utc),
            stop: stop.then(|| Utc.timestamp_opt(1, 0).unwrap()),
            duration,
            billable,
            workspace_id: 1,
            tags: Vec::new(),
            project: None,
            task: None,
            created_with: None,
        }
    }

    #[test]
    fn aggregates_stopped_billable_entries_with_per_entry_rounding() {
        let entries = vec![
            entry("2026-01-05T23:30:00Z", 901, true, true),
            entry("2026-01-06T00:30:00Z", 1, true, true),
            entry("2026-01-06T01:00:00Z", 3600, false, true),
            entry("2026-01-06T02:00:00Z", -1, true, false),
        ];

        let weeks = aggregate(&entries);

        assert_eq!(
            weeks.get(&NaiveDate::from_ymd_opt(2026, 1, 5).unwrap()),
            Some(&2700)
        );
        assert_eq!(weeks.len(), 1);
    }

    #[test]
    fn uses_utc_date_for_iso_week() {
        let entries = vec![entry("2026-01-05T00:30:00+02:00", 60, true, true)];

        let weeks = aggregate(&entries);

        assert!(weeks.contains_key(&NaiveDate::from_ymd_opt(2025, 12, 29).unwrap()));
    }
}

